CREATE TABLE Customer (customer_id TEXT PRIMARY KEY, full_name TEXT NOT NULL, email TEXT, phone TEXT, address TEXT, city TEXT NOT NULL, state TEXT NOT NULL, pincode TEXT NOT NULL, created_at TIMESTAMP NOT NULL); CREATE TABLE Order (order_id TEXT PRIMARY KEY, order_date TIMESTAMP NOT NULL, cust_id TEXT NOT NULL, FOREIGN KEY (cust_id) REFERENCES Customer(customer_id)); CREATE TABLE OrderItem (order_id TEXT NOT NULL, prod_id TEXT NOT NULL, qty INTEGER NOT NULL, price NUMERIC NOT NULL, PRIMARY KEY (order_id, prod_id), FOREIGN KEY (order_id) REFERENCES Order(order_id)); CREATE TABLE Product (prod_id TEXT PRIMARY KEY, prod_name TEXT NOT NULL, category TEXT); CREATE TABLE Payment (payment_id TEXT PRIMARY KEY, order_id TEXT NOT NULL, method TEXT NOT NULL, amount NUMERIC NOT NULL, currency TEXT NOT NULL, status TEXT NOT NULL, paid_at TIMESTAMP, status_date TIMESTAMP, FOREIGN KEY (order_id) REFERENCES Order(order_id)); CREATE TABLE Shipping (tracking_id TEXT PRIMARY KEY, order_id TEXT NOT NULL, shipped_date TIMESTAMP, carrier TEXT, location TEXT, FOREIGN KEY (order_id) REFERENCES Order(order_id));